</template>

<script>
var name = [];
import DataService from "../../services/DataService";
import modalConfigureQuote from '../../components/Common/Modal/modalConfigureQuote.vue';
import modalConfigureCRM from '../../components/Common/Modal/modalConfigureCRM.vue';
import modalConfigureClient from "../../components/Common/Modal/modalConfigureClient.vue";
import modalConfigureClientBill from "../../components/Common/Modal/modalConfigureClientBill.vue";
import authService from "../../services/authservice";

export default {
    components: {
        modalConfigureQuote,
        modalConfigureCRM,
        modalConfigureClient,
        modalConfigureClientBill

    },
    props: {
        fromDate: {
            type: Object,
        },
        ToDate: {
            type: Object,
        },

    },
    data() {
        return {
            activeKey: 0,
            moduleddata: [],
            moduleddataAll: [],
            searchQuery: "",
            modulename: "",
            moduletitle: [],
            classicon: [],
            activeKey: null,
            moduleKeys: [],
            validate: [],
            saveArray: [],
            showsavebutton: false,
            classadded: '',
            isLoading: false,
            dynamicclass: '',
            selectedModule: null,
            IsSearchItem: false,
            id: null,
            attachmentDiv: '',
            blobUrl: '',
            imgPath: '',
            UserType: '',
            CompanyLogoCoreConfigId: 0,
            timeZoneData: [],
            getTimeZone: '',
            timeZoneKeys: 0,
            Month: '',
            year: '',
            Number: '',
            arraydata: [],
            defaultdata: [],
            opennumbering: false,
            openConfigureClientNumbering: false,
            CheckBoxClass: '',
            configureType: '',
            salesorderdata: [],
            shiftData: [],
            designData: [],
            departData: [],
            locationData: [],
            currencyData: [],
            showMobileTabs: false,
            currentTab: "Approval".toLowerCase(),
            openClientBillNumbering: false,
            IsConfigureClientBill: false,

        };
    },
    computed: {
        GetSelectedModuleItem() {
            var ths = this;
            var getModuleObj = ths.moduleddata.filter((x) => {
                return x.moduleTitle.toLowerCase() == ths.currentTab.toLowerCase();
            });

            // Return the first element if found, otherwise return an empty object or a default object
            return getModuleObj.length > 0 ? getModuleObj[0] : { classicon: '', moduleTitle: '' };
        }
    },
    created() {
        var vm = this;

        vm.UserType = vm.GetUserInfo.UserType;
        vm.containerName = vm.GetUserInfo.ContainerName;
        vm.GetLeftModulesdata();

    },

    methods: {
        SetCurrentTab: function (moduleName, itm) {
            this.currentTab = moduleName.toLowerCase();
            this.activateTab(itm);
        },
        TruncateStr(str, len) {
            var convertstring = '' + str;
            if (convertstring != null)
                if (convertstring.length <= len) return str;
                else return convertstring.substring(0, len) + "...";
        },
        Clearimagevalue: function () {
            var vm = this;
            vm.attachmentDiv = '';
        },
        AddClass: function (id, cls) {
            var checkBoxId = id
            if ($('#' + id)[0].className.split(' ')[1] == 'check') {
                $('#' + id).removeClass('check')
            } else {
                $('#' + id).addClass('check')
            }
        },
        GetCheckBoxValue: function (data, ind) {
            return data.split('^')[ind]
        },
        GetTimeZone: function () {
            var vm = this;
            DataService.GetTimeZone().then(function (response) {
                vm.timeZoneData = response.data;

            })
        },
        GetCurrencyData() {
            var vm = this;
            DataService.GetCurrency().then((response) => {
                if (response.data != null) {
                    vm.currencyData = response.data;
                }
            })
        },
        GetShiftData() {
            var vm = this;
            DataService.GetAllShift().then((response) => {
                if (response.data != null) {

                    vm.shiftData = response.data;
                }
            })
        },
        GetDepartmentData() {
            var vm = this;
            DataService.GetAllDepartment().then((response) => {
                if (response.data != null) {
                    vm.departData = response.data;
                }
            })
        },
        GetLocation() {
            var vm = this;
            DataService.GetCompanyLocation().then((response) => {
                if (response.data != null) {
                    vm.locationData = response.data;
                }
            })
        },
        GetDesignationData() {
            var vm = this;
            DataService.GetAllDesignation().then((response) => {
                if (response.data != null) {
                    vm.designData = response.data;
                }
            })
        },
        GetSalesOrder() {
            var vm = this;
            DataService.TemplateListForSalesOrder().then((response) => {
                if (response.data != null) {

                    vm.salesorderdata = JSON.parse(response.data);
                }
            })
        },
        GetDefaultTempData() {
            var vm = this;
            var param = `categoryName=Invoice`
            DataService.TemplateListByCategory(param).then((response) => {
                if (response.data != null) {
                    if (response.data.length > 0) {
                        vm.defaultdata = JSON.parse(response.data);

                    }
                }
            })
        },
        setFile: function (values, meta, e) {
            this.attachmentDiv = e.target.files[0].name;
            this.fileName = e.target.files[0];
            this.arrayGetFileDetails = e.target.files[0];
        },
        ClearImage: function () {
            this.blobUrl = 'http://localhost:9000/' + '/Content/images/DefaultImages/company-logo.jpg'
            this.defaultCompanyLogo = 'COMPANY-LOGO.JPG'
        },

        GetBlobUrl: function () {
            debugger;
            var vm = this;
            DataService.GetBlobUrl().then((response) => {
                debugger;
                var url = response.data[0].CONFIG_DATA_VALUE;
                var usertype = this.UserType;
                if (vm.imgPath.toUpperCase() == "COMPANY-LOGO.JPG") {

                    vm.blobUrl = 'http://localhost:9000/' + '/Content/images/DefaultImages/company-logo.jpg'
                }
                if (usertype == "CA" && this.imgPath.toUpperCase() != "COMPANY-LOGO.JPG") {
                    vm.blobUrl = url + '/' + this.containerName + '/' + 'Upload' + '/' + 'CompanyLogo' + '/' + vm.imgPath
                }
            })
        },
        modalConfigureQuote: function (id) {
            this.id = id;
            this.IsSearchItem = true;
        },

        openmoadalConfigureCRM: function (id) {
            this.id = id;
            this.opennumbering = true;
        },
        openmoadalConfigureClientBill(id) {
            // debugger
            this.id = id;
            this.IsConfigureClientBill = true;
        },
        ClosemodalConfigureClientBill: function () {
            this.IsConfigureClientBill = false;
        },
        openModalConfigureClient: function (id, type) {
            this.id = id;
            this.configureType = type;
            this.openConfigureClientNumbering = true;
        },
        ClosemodalConfigurecrmNumbering: function () {
            this.opennumbering = false;
        },
        CloseConfigureClientNumbering: function () {
            this.openConfigureClientNumbering = false;
        },
        ClosemodalConfigureQuote: function () {
            this.IsSearchItem = false;
        },

        filteredCustomField: function (e) {
            var vm = this
            if (vm.searchQuery == '') {
                vm.moduleddata = vm.moduleddataAll;
            } else {
                let CheckIfExist = vm.moduleddataAll.filter(item => item.moduleTitle.toLowerCase().includes(vm.searchQuery.toLowerCase()));
                vm.moduleddata = CheckIfExist;
            }
            if (vm.moduleddata.length > 0) {
                setTimeout(function () {
                    vm.activateTab(vm.moduleddata[0]);
                }, 100);
            }
        },
        // Getoption: function (params) {

        //     params = params == null ? "" : params;
        //     var options = [];
        //     $.each(params.split("^"), function (i, v) {
        //         options.push(v);
        //     });
        //     return options;
        // },
        Getoption: function (params) {
            params = params == null ? "" : params;
            var options = [];
            $.each(params.split("^"), function (i, v) {
                if (!v) return;
                if (v.toLowerCase() === 'yes') {
                    options.push('Yes');
                }
                else if (v.toLowerCase() === 'no') {
                    options.push('No');
                }
                else {
                    options.push(v);
                }
            });
            return options;
        },

        async saveStorageConfiguration() {
            var vm = this;
            vm.objData = [];
            var dataString = '';
            var finalString = ''
            vm.isLoading = true
            //var params = `keyValue=&moduleId=${vm.activeKey}&IsWizard=`;
            var textValues = $('div#ulKeysContainer input:text,div#ulKeysContainer select,div#ulKeysContainer textarea,div#ulKeysContainer input:password'); //get all textboxes,textarea and drop down list from config list
            var checkBoxValues = $('div#ulKeysContainer div[type="checkbox"], div#ulKeysContainer div[type="radiobutton"]');
            for (var i = 0; i < textValues.length; i++) {
                if ($(textValues[i]).attr('keys') != undefined) {
                    if ($(textValues[i]).val() != null && $(textValues[i]).val() != "") {
                        var textValue = $(textValues[i]).val().trim();
                    } else {
                        var textValue = '!~~!'
                    }
                    dataString = $(textValues[i]).attr('keys') + '||' + textValue + '||' + $(textValues[i]).attr('keyName');
                }
                finalString += dataString + '::'
            }
            for (var i = 0; i < checkBoxValues.length; i++) {
                var getSelectedvalues = '';
                if ($(checkBoxValues[i]).attr('keys') != undefined && $(checkBoxValues[i]).attr('keys') != 'undefined') {
                    if ($(checkBoxValues[i]).attr('type') == 'radiobutton') {
                        var combinedName = ("config" + i);
                        //getSelectedvalues = $("input[name='"+combinedName+"']:checked").val();
                        getSelectedvalues = $(checkBoxValues[i]).find('input:radio:checked').val();
                        dataString = $(checkBoxValues[i]).attr('keys') + '||' + getSelectedvalues + '||' + $(checkBoxValues[i]).attr('keyName')
                    }
                    if ($(checkBoxValues[i]).find('input:checkbox').each(function () {

                        if ($(this).next("label").attr("class").split(' ')[1] == "check") {
                            getSelectedvalues = getSelectedvalues + $(this).val() + '^';
                            dataString = $(checkBoxValues[i]).attr('keys') + '||' + getSelectedvalues + '||' + $(checkBoxValues[i]).attr('keyName');
                        }
                    }));
                    let radioConfigDatas = {
                        DataId: $(checkBoxValues[i]).attr('keys'),
                        DataValue: getSelectedvalues
                    }
                    vm.objData.push(radioConfigDatas);
                    let jsonObject = vm.objData.map(JSON.stringify);
                    let uniqueSet = new Set(jsonObject);
                    vm.allConfigObject = Array.from(uniqueSet).map(JSON.parse);
                }
                finalString += dataString + '::'
            }
            var imageControl = $('#flFile').val();

            // Check if imageControl has a value
            if (imageControl) {
                var splitimage = imageControl.split('\\')[2];

                // Check if splitimage is not undefined and vm.defaultCompanyLogo is null
                if (splitimage && vm.defaultCompanyLogo == null) {
                    // Assuming vm.CompanyLogoCoreConfigId, imageControl, and 'NA' are defined somewhere in your code
                    var dataString = vm.CompanyLogoCoreConfigId + '||' + imageControl + '||' + 'NA';
                    finalString += dataString + '::';
                } else if (vm.defaultCompanyLogo != null) {
                    // Assuming vm.CompanyLogoCoreConfigId and 'COMPANY-LOGO.JPG' are defined somewhere in your code
                    var dataString = vm.CompanyLogoCoreConfigId + '||' + 'COMPANY-LOGO.JPG' + '||' + 'NA';
                    finalString += dataString + '::';
                }
            }

            vm.$refs.configuration.validate().then(result => {
                if (result) {
                    var params = `moduleId=${this.activeKey}&keyValue=${encodeURIComponent(finalString)}&IsWizard=`;
                    DataService.ModuleValidationMessages(params).then((response) => {
                        vm.validate = response.data.status
                        if (vm.validate == 0) {
                            // debugger
                            vm.update(this.activeKey, finalString, this.fileName);
                            //debugger
                            if (vm.selectedModule.moduleTitle === 'General') {
                                authService.signIn(this.$route.path).then(() => { });
                            }
                        }
                        vm.isLoading = false
                    })
                } else {
                    vm.isLoading = false;
                }
            })
        },

        async update(Id, string, file) {
            var vm = this;
            vm.isLoading = true
            const formdata = new FormData();
            formdata.append("Files", file);
            formdata.append("moduleId", Id)
            formdata.append("keyValue", string)
            await DataService.UpdateCompanySetupConfig(formdata).then((response) => {
                vm.saveArray = response.data
                if (vm.saveArray.status == 1) {
                    vm.isLoading = false
                    vm.ShowAlert(vm.$t("RecordsSavedSuccessfully"), 'success', true, vm.$t('Alert'));
                    vm.activateTab();

                } else {
                    vm.isLoading = false
                }

            });
        },
        async GetLeftModulesdata() {
            var vm = this;
            await DataService.GetAllModule().then((response) => {
                vm.moduleddata = response.data;
                debugger
                vm.moduleddataAll = vm.moduleddata;
                vm.moduleddata.forEach((item) => {
                    if (item.moduleTitle.toLowerCase().includes(vm.searchQuery.toLowerCase())) {
                        item.isVisible = true;
                    } else {
                        item.isVisible = false;
                    }
                    switch (item.moduleTitle) {
                        case "Approval":
                            item.classicon = "fa fa-thumbs-up action-icon";
                            break;
                        case "Client Bill":
                            item.classicon = "fa fa-sticky-note action-icon";
                            break;
                        case "Clients":
                            item.classicon = "fa fa-users action-icon";
                            break;
                        case "Cloud Storage":
                            item.classicon = "fa fa-database action-icon";
                            break;
                        case "CRM":
                            item.classicon = "fa fa-tasks action-icon";
                            break;
                        case "Emails":
                            item.classicon = "fa fa-envelope action-icon";
                            break;
                        case "Expense Approval":
                            item.classicon = "fa fa-check action-icon";
                            break;
                        case "Expenses":
                            item.classicon = "fa fa-money action-icon";
                            break;
                        case "General":
                            item.classicon = "fa fa-cog action-icon";
                            break;
                        case "Hiring":
                            item.classicon = "fa fa-list-alt action-icon";
                            break;
                        case "Human Resource":
                            item.classicon = "fa fa-user action-icon";
                            break;
                        case "Knowledge Base":
                            item.classicon = "fa fa-book action-icon";
                            break;
                        case "Microsoft Exchange":
                            item.classicon = "fa fa-windows action-icon";
                            break;
                        case "Product Management":
                            item.classicon = "fa fa-building action-icon";
                            break;
                        case "Project":
                            item.classicon = "fa fa-thumbs-up action-icon";
                            break;
                        case "Project files":
                            item.classicon = "fa fa-folder-open action-icon";
                            break;
                        case "Project Message Board":
                            item.classicon = "fa fa-comment action-icon";
                            break;
                        case "Quote":
                            item.classicon = "fa fa-file-text action-icon";
                            break;
                        case "Storage":
                            item.classicon = "fa fa-database action-icon";
                            break;
                        case "Ticketing":
                            item.classicon = "fa fa-street-view action-icon";
                            break;
                        case "Time Tracker":
                            item.classicon = "fa fa-clock-o action-icon";
                            break;
                        case "Timesheet":
                            item.classicon = "fa fa-calendar action-icon";
                            break;
                        case "Training":
                            item.classicon = "fa fa-pencil-square action-icon";
                            break;
                        case "Work Diary":
                            item.classicon = "fa fa-picture-o action-icon";
                            break;
                        default:
                            item.classicon = "fa fa-pencil";
                    }
                });
                if (vm.moduleddata.length > 0) {
                    setTimeout(function () {
                        vm.activateTab(vm.moduleddata[0]);
                    }, 100);
                }
            });
        },
        async activateTab(item) {
            debugger;
            var vm = this;
            vm.isLoading = true;
            if (item != undefined) {
                vm.dynamicclass = item.classicon
                vm.showsavebutton = true;
                vm.modulename = item.moduleTitle;
                vm.activeKey = item.moduleId;
                vm.selectedModule = item;
                console.log("Seelcted Module", vm.selectedModule)
            }
            var params = `moduleId=${vm.activeKey}&IsWizard=`;
            await DataService.GetKeys(params).then(async (response) => {
                debugger
                if (response.data.keyList.length > 0) {
                    //vm.moduleKeys = response.data.keyList

                    if (response.data.keyList.length > 0) {
                        vm.moduleKeys = response.data.keyList.map(item => {
                            if (item.coreConfigType === "radiobutton" && item.coreConfigValue) {
                                const value = item.coreConfigValue.toLowerCase();
                                item.coreConfigValue = value.charAt(0).toUpperCase() + value.slice(1);
                            }
                            return item;
                        });
                    }

                    await this.setDynamicValues(vm.moduleKeys, 4);
                    vm.GetBlobUrl();
                    vm.GetTimeZone();
                    vm.GetDefaultTempData();
                    vm.GetSalesOrder();
                    vm.GetShiftData();
                    vm.GetDesignationData();
                    vm.GetLocation();
                    vm.GetDepartmentData();
                    vm.GetCurrencyData();
                }
                vm.isLoading = false;

            })

        },
        setDynamicValues(moduleKeys, indexToCheck) {
            //debugger;
            const logoConfig = moduleKeys.find(item => item.coreConfigKey === "CompanyLogo");
            if (logoConfig) {
                this.imgPath = logoConfig.coreConfigValue || '';
                this.CompanyLogoCoreConfigId = logoConfig.coreConfigId || '';
            } else {
                this.imgPath = '';
                this.CompanyLogoCoreConfigId = '';
            }
            //if (moduleKeys.length > indexToCheck && moduleKeys[indexToCheck]) {

            //if(moduleKeys[indexToCheck].coreConfigKey=="CompanyLogo")
            //{
            // this.imgPath = moduleKeys[indexToCheck].coreConfigValue || '';
            //}
            //else
            //{
            //this.imgPath = moduleKeys[indexToCheck].coreConfigValue || '';
            //this.CompanyLogoCoreConfigId = moduleKeys[indexToCheck].coreConfigId || '';
            //}
            //} else {
            //this.imgPath = '';
            //this.CompanyLogoCoreConfigId = '';
            //}
        }
    },

};
</script>

